5	  // --- Empty / trivial quote ---
6	  it("quote with empty item list returns premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single item base premiums (with newcomer first-insurance and fee folded in) ---
15	  it.todo("quote for single plain sword (newcomer, 0 years) returns premium 115 G (100 base + 10 first-insurance + 5 fee)");
16	  it.todo("quote for single plain amulet (newcomer) returns premium 71 G (60 base + 6 first-insurance + 5 fee)");
17	  it.todo("quote for single plain staff (newcomer) returns premium 93 G (80 base + 8 first-insurance + 5 fee)");
18	  it.todo("quote for single plain potion (newcomer) returns premium 49 G (40 base + 4 first-insurance + 5 fee)");
19	
20	  // --- Component base premiums (building block of 3) ---
21	  it.todo("quote for 2 runes returns base premium 50 G before policy-wide modifiers (50 + 5 first-insurance + 5 fee = 60 G)");
22	  it.todo("quote for 3 runes applies block: base premium 60 G (60 + 6 first-insurance + 5 fee = 71 G)");
23	  it.todo("quote for 4 runes returns base premium 100 G — no block since block requires exactly 3 (100 + 10 first-insurance + 5 fee = 115 G)");
24	  it.todo("quote for 7 runes returns base premium 175 G (one block of 3 = 60 G + 4 runes × 25 G = 100 G; 175 + 18 first-insurance + 5 fee = 198 G)");
25	
26	  // --- 'Alike' components clarification ---
27	  it.todo("quote for 2 runes + 1 moonstone returns base premium 75 G — no block since types differ (75 + 8 first-insurance + 5 fee = 88 G)");
28	  it.todo("quote for 3 runes + 3 moonstones returns base premium 120 G — two separate blocks (120 + 12 first-insurance + 5 fee = 137 G)");
29	
30	  // --- Item-specific modifier: cursed (applies to that item only) ---
31	  it.todo("quote for cursed sword + plain amulet (newcomer) returns policy base 160 G + 50 G curse on the sword's 100 G base, then first-insurance and fee");
32	
33	  // --- Modifier thresholds ---
34	  it.todo("quote for sword with enchantment exactly 5 applies high-enchantment surcharge (30 % of base premium)");
35	  it.todo("quote for sword with enchantment 4 does NOT apply high-enchantment surcharge");
36	  it.todo("quote for cursed sword with enchantment exactly 5 applies both cursed and high-enchantment surcharges");
37	  it.todo("quote with customer who has exactly 2 years with MHPCO applies the 20 % loyalty discount");
38	
39	  // --- Integration: newcomer with a cursed sword (spec example) ---
40	  it.todo("integration: newcomer (0 years, first contract) cursed sword (steel, enchantment 3) returns premium 165 G");
41	
42	  // --- Integration: long-standing customer's second contract (spec example) ---
43	  it.todo("integration: 3-years customer, 2nd quote in scenario, cursed sword (steel, enchantment 7) returns premium 160 G (loyalty + follow-up + curse + high enchantment + first-insurance per item + fee)");
44	
45	  // --- Rounding in MHPCO's favor ---
46	  it.todo("premium calculation that yields 197.5 G is rounded UP to 198 G");
47	  it.todo("payout calculation that yields 350.5 G is rounded DOWN to 350 G");
48	
49	  // --- Claim: standard reimbursement (no special clauses) ---
50	  it.todo("claim on plain steel sword (enchantment 3) with 500 G damage: payout 400 G (full minus 100 G deductible)");
51	  it.todo("claim on a rune (insurance value 250 G) with 200 G damage: payout 100 G (full minus 100 G deductible; runes have no enchantment/material clauses)");
52	
53	  // --- Claim: high-enchantment clause ---
54	  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");
55	
56	  // --- Claim: dragon-material clause ---
57	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
58	
59	  // --- Claim: both clauses — 50 % rule wins ---
60	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
61	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");
62	
63	  // --- Claim: deductible per damage event (multi-item single incident) ---
64	  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");
65	
66	  // --- Claim: cap = 2 × insurance sum ---
67	  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
68	  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
69	  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");
70	
71	  // --- Claim: cap exhaustion across successive claims ---
72	  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
73	  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");
74	
75	  // --- Claim: multiple items of the same type ---
76	  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
77	  it.todo("claim on two swords (two separate damage entries) treats each entry as separate damage with its own deductible");
78	  it.todo("claim contains more entries of a given type than the policy covers: the whole claim is rejected (error)");
79	
80	  // --- Edge cases / errors ---
81	  it.todo("quote includes an item with unknown type (e.g. broomstick): error, no results");
82	  it.todo("claim references an item not part of the policy (e.g. amulet damage when only a sword is insured): error");
83	  it.todo("claim with a negative damage amount (amount: -200): error");
84	});
